import { motion } from "motion/react";

type ServicePartProps = {
  img: string;
  alt: string;
  name: string;
  description: string;
  suitableFor: string;
  onReserveClick: () => void;
}

export default function ServicePart({ img, alt, name, description, suitableFor, onReserveClick }: ServicePartProps): JSX.Element {
  return (
    <div className="col-md-3 mb-4 py-1">
      <motion.div
        style={{ height: "100%" }}
        initial={{ y: 50, opacity: 0 }}
        whileInView={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.8, ease: "easeOut" }}
        viewport={{ once: true }}>
        <div
          className="card h-100 border-0 bg-light hover-shadow cursor-pointer"
          onClick={onReserveClick}
          role="button"
          tabIndex={0}
          onKeyDown={(e) => {
            if (e.key === "Enter") onReserveClick();
          }}
        >
          <div className="card-body h-100 d-flex flex-column justify-content-between">
            <img
              src={img}
              alt={alt}
              className="rounded-circle mx-auto mb-2"
              style={{ width: '90px', height: '90px', objectFit: 'cover', }} />
            <h5 className="card-title text-center mb-3 py-2 fw-bold">{name}</h5>
            <p className="card-text"> {description}</p>
            <p className="card-text"> 適用對象：{suitableFor}</p>
            <button className="btn btn-primary rounded-0 fw-bold text-white" >LINE 預約諮詢</button>
          </div>
        </div>
      </motion.div>
    </div>)
}
